import React from 'react';
import { Card, CardContent, Typography, Stack, Chip, Box } from '@mui/material';
import { ArrowUpward } from '@mui/icons-material';
import response from './response.json';

interface OrderProgress {
  stage: string;
  completed: boolean;
}

interface DriverLocation {
  latitude: number;
  longitude: number;
}

interface Driver {
  name: string;
  location: DriverLocation;
}

interface Order {
  status: string;
  estimatedDelivery: string;
  driver: Driver;
  orderProgress: OrderProgress[];
}

interface ResponseData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    order: Order;
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const responseData = response.data as ResponseData;
  const { order } = responseData.data;
  const { primaryColor, accentColor } = responseData.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="text.primary" sx={{ mb: 1 }}>
              Order Status
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Status: {order.status}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Estimated Delivery: {order.estimatedDelivery}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Driver: {order.driver.name}
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {order.orderProgress.map((progress, index) => (
                <Chip
                  key={index}
                  label={progress.stage}
                  icon={progress.completed ? <ArrowUpward sx={{ fontSize: 16, color: primaryColor }} /> : null}
                  sx={{
                    fontSize: '11px',
                    color: progress.completed ? primaryColor : undefined,
                    bgcolor: progress.completed ? accentColor : undefined,
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
